import path from "path";
import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  turbopack: {
    root: path.join(__dirname, "../.."),
  },
  images: {
    formats: ["image/avif", "image/webp"],
  },
  compress: true,
};

export default nextConfig;

import type { Metadata } from "next";
import { Geist, Geist_Mono, Noto_Sans_JP } from "next/font/google";
import { NuqsAdapter } from "nuqs/adapters/next/app";
import { Analytics } from "@vercel/analytics/next";

import { AgeAcknowledgmentBar } from "@/components/age-acknowledgment-bar";
import { SiteFooter } from "@/components/site-footer";
import { SiteHeader } from "@/components/site-header";
import { buildSiteVerification } from "@/lib/site-verification";
import { getSiteOrigin } from "@/lib/site";

import "./globals.css";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

const notoSansJP = Noto_Sans_JP({
  variable: "--font-noto-sans-jp",
  subsets: ["latin"],
  weight: ["400", "500", "600", "700"],
  display: "swap",
});

const siteOrigin = getSiteOrigin();
const siteVerification = buildSiteVerification();

export const metadata: Metadata = {
  metadataBase: new URL(siteOrigin),
  title: {
    default: "宝くじAI | ナンバーズ3・4 抽選結果と参加支援（モデル試算）",
    template: "%s · 宝くじAI",
  },
  description:
    "ナンバーズ3・4の当選番号・抽選結果の閲覧に加え、ナンバーズ4では複数モデルの日次「試算」出力や統計を一覧できます。当せんの保証や購入の推奨は行いません（参加の情報整理・戦略検討の補助）。（takarakuji-ai.space） English: Unofficial Japan Numbers3/4 dashboard — results and reference model outputs; not affiliated with any operator.",
  applicationName: "宝くじAI",
  keywords: [
    "ナンバーズ3",
    "ナンバーズ３",
    "ナンバーズ4",
    "ナンバーズ４",
    "宝くじ",
    "抽選結果",
    "当選番号",
    "予測",
    "モデル試算",
    "参加戦略",
    "宝くじAI",
    "ブログ",
    "FAQ",
    "Numbers3",
    "Numbers4",
    "Numbers 4",
    "Japan lottery",
    "Japanese lottery",
    "Takarakuji",
    "lottery results",
    "winning numbers",
    "lottery statistics",
    "machine learning",
    "lottery analytics",
    "digit lottery",
    "اليانصيب الياباني",
    "نمبرز 4",
  ],
  authors: [{ name: "宝くじAI" }],
  creator: "宝くじAI",
  openGraph: {
    type: "website",
    locale: "ja_JP",
    alternateLocale: ["en_US", "zh_CN", "ko_KR", "es_ES", "hi_IN", "ar_SA"],
    url: siteOrigin,
    siteName: "宝くじAI",
    title: "宝くじAI | ナンバーズ3・4 抽選結果と参加支援（モデル試算）",
    description:
      "ナンバーズ3の当選一覧（等級つき）と、ナンバーズ4の当選番号・日次モデル試算・統計をスマホでも見やすく。当せんを約束するサービスではありません。",
  },
  twitter: {
    card: "summary_large_image",
    title: "宝くじAI",
    description:
      "ナンバーズ3・4の抽選結果と、モデル試算・統計のダッシュボード。当せんの保証はありません。",
  },
  alternates: {
    types: {
      "application/rss+xml": "/feed.xml",
    },
  },
  robots: {
    index: true,
    follow: true,
    googleBot: {
      index: true,
      follow: true,
      "max-video-preview": -1,
      "max-image-preview": "large",
      "max-snippet": -1,
    },
  },
  ...(siteVerification ? { verification: siteVerification } : {}),
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html
      lang="ja"
      className={`${geistSans.variable} ${geistMono.variable} ${notoSansJP.variable} h-full antialiased`}
    >
      <body className="flex min-h-full flex-col">
        <NuqsAdapter>
          <div className="app-surface app-dot-grid flex min-h-full flex-1 flex-col">
            <SiteHeader />
            <main className="flex flex-1 flex-col">{children}</main>
            <SiteFooter />
            <AgeAcknowledgmentBar />
          </div>
        </NuqsAdapter>
        <Analytics />
      </body>
    </html>
  );
}

import type { Metadata } from "next";

import { HomeLanding } from "@/components/home-landing";
import { absoluteUrl, getSiteOrigin } from "@/lib/site";

export const metadata: Metadata = {
  alternates: {
    canonical: "/",
    languages: {
      ja: absoluteUrl("/"),
      en: absoluteUrl("/en"),
      zh: absoluteUrl("/zh"),
      ko: absoluteUrl("/ko"),
      es: absoluteUrl("/es"),
      hi: absoluteUrl("/hi"),
      ar: absoluteUrl("/ar"),
    },
  },
  openGraph: {
    url: getSiteOrigin(),
    title: "宝くじAI | ナンバーズ3・4・ロト6の本気ダッシュボード",
    description:
      "ナンバーズ3・ロト6の当選一覧（等級・払戻つき）と、ナンバーズ4のマルチモデル試算・統計・トレンドまで。当せんの保証はなく、参加の情報整理を支援する非公式ダッシュボードです。",
  },
};

const homeJsonLd = {
  "@context": "https://schema.org",
  "@graph": [
    {
      "@type": "WebSite",
      "@id": `${getSiteOrigin()}/#website`,
      url: getSiteOrigin(),
      name: "宝くじAI",
      alternateName: [
        "Takarakuji AI",
        "takarakuji-ai.space",
        "تاكاراكوجي AI",
        "Japan Numbers3, Numbers4 & Loto6 lottery dashboard",
        "لوحة يانصيب أرقام اليابان",
      ],
      description:
        "ナンバーズ3・4・ロト6の当選番号・抽選結果の閲覧と、複数モデルによる日次試算出力・統計・トレンド可視化をまとめたWebアプリ（当せん保証・購入推奨はしません）。 English: Unofficial Japan Numbers3/4/Loto6 results and reference analytics; see /en and /ar for overviews.",
      inLanguage: "ja",
      publisher: { "@id": `${getSiteOrigin()}/#organization` },
    },
    {
      "@type": "Organization",
      "@id": `${getSiteOrigin()}/#organization`,
      name: "宝くじAI",
      url: getSiteOrigin(),
      sameAs: [] as string[],
    },
  ],
};

export default function Home() {
  return (
    <div className="flex flex-1 flex-col">
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{
          __html: JSON.stringify(homeJsonLd),
        }}
      />
      <HomeLanding />
    </div>
  );
}

