14	import { getSiteOrigin } from "@/lib/site";
15	import { NUMBERS4_PAGE_SIZE, type Numbers4DrawRow } from "@/lib/numbers4";
16	
17	import { buildWinningModelHitsForDrawList } from "@/lib/numbers4-predictions/load-6949";
18	
19	import { Numbers4DrawsTable } from "./numbers4-draws-table";
20	import { Numbers4Pagination } from "./numbers4-pagination";
21	import { Numbers4RecentModelHits } from "./numbers4-recent-model-hits";
22	
23	export const dynamic = "force-dynamic";
24	
25	export const metadata: Metadata = {
26	  title: "ナンバーズ4 当選番号一覧",
27	  description:
28	    "ナンバーズ4の過去の抽選結果（当選番号・等級別口数・払戻金）を一覧表示します。 EN: Past Numbers4 winning numbers list (unofficial; verify with Mizuho / official sources).",
29	  alternates: { canonical: "/numbers4/result" },
30	  openGraph: {
31	    title: "ナンバーズ4 当選番号一覧 | 宝くじAI",
32	    description:
33	      "過去の抽選結果を一覧で確認。日次モデル試算との照合表示にも対応（当せん保証なし）。",
34	    url: "/numbers4/result",
35	  },
36	};
37	
38	type PageProps = {
39	  searchParams: Promise<{ page?: string }>;
40	};
41	
42	function parsePage(raw: string | undefined): number {
43	  const n = parseInt(raw ?? "1", 10);
44	  if (!Number.isFinite(n) || n < 1) return 1;
45	  return n;
46	}
47	
48	export default async function Numbers4ResultPage({ searchParams }: PageProps) {
49	  const { page: pageParam } = await searchParams;
50	  const requestedPage = parsePage(pageParam);
51	
52	  const supabase = await createClient();
53	
54	  const { count, error: countError } = await supabase
55	    .from("numbers4_draws")
56	    .select("*", { count: "exact", head: true });
57	
58	  if (countError) {
59	    throw new Error(countError.message);
60	  }
61	
62	  const totalCount = count ?? 0;
63	  const totalPages = Math.max(1, Math.ceil(totalCount / NUMBERS4_PAGE_SIZE));
64	
65	  if (requestedPage > totalPages && totalCount > 0) {
66	    redirect(`/numbers4/result?page=${totalPages}`);
67	  }
68	
69	  const page = Math.min(requestedPage, totalPages);
70	  const from = (page - 1) * NUMBERS4_PAGE_SIZE;
71	  const to = from + NUMBERS4_PAGE_SIZE - 1;
72	
73	  const { data, error } = await supabase
74	    .from("numbers4_draws")
75	    .select("*")
76	    .order("draw_number", { ascending: false })
77	    .range(from, to);
78	
79	  if (error) {
80	    throw new Error(error.message);
81	  }
82	
83	  const rows = (data ?? []) as Numbers4DrawRow[];
84	
85	  const { data: recentForHits, error: recentHitsError } = await supabase
86	    .from("numbers4_draws")
87	    .select("draw_number, numbers")
88	    .not("numbers", "is", null)
89	    .order("draw_number", { ascending: false })
90	    .limit(100);
91	
92	  if (recentHitsError) {
93	    throw new Error(recentHitsError.message);
94	  }
95	
96	  const recentHitRows = (recentForHits ?? []) as Pick<
97	    Numbers4DrawRow,
98	    "draw_number" | "numbers"
99	  >[];
100	  const winningModelHits = await buildWinningModelHitsForDrawList(
101	    recentHitRows.map((r) => ({
102	      draw_number: r.draw_number,
103	      numbers: r.numbers,
104	    })),
105	  );
106	
107	  const breadcrumbJsonLd = buildBreadcrumbJsonLd([
108	    { name: "ナンバーズ4", path: "/numbers4" },
109	    { name: "当選番号一覧", path: "/numbers4/result" },
110	  ]);
111	
112	  const origin = getSiteOrigin();
113	  const datasetJsonLd = {
114	    "@context": "https://schema.org",
115	    "@type": "Dataset",
116	    name: "ナンバーズ4 当選番号データセット",
117	    alternateName: "Numbers4 Draw Results Dataset",
118	    description:
119	      "日本のナンバーズ4の過去の抽選結果（当選番号・等級別口数・払戻金）を収録したデータセット。公開データから取得。",
120	    url: `${origin}/numbers4/result`,
121	    license: "https://creativecommons.org/publicdomain/zero/1.0/",
122	    creator: {
123	      "@type": "Organization",
124	      name: "宝くじAI",
125	      url: origin,
126	    },
127	    distribution: [
128	      {
129	        "@type": "DataDownload",
130	        encodingFormat: "application/json",
131	        contentUrl: `${origin}/api/numbers4/latest`,
132	      },
133	    ],
134	    temporalCoverage: "..",
135	    keywords: [
136	      "Numbers4",
137	      "ナンバーズ4",
138	      "lottery",
139	      "宝くじ",
140	      "draw results",
141	      "当選番号",
142	      "Japan",
143	    ],
144	  };
145	
146	  return (
147	    <div className="flex flex-1 flex-col">
148	      <script
149	        type="application/ld+json"
150	        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
151	      />
152	      <script
153	        type="application/ld+json"
154	        dangerouslySetInnerHTML={{ __html: JSON.stringify(datasetJsonLd) }}
155	      />
156	      <div className="mx-auto w-full max-w-[1600px] flex-1 space-y-8 px-4 py-8 sm:space-y-10 sm:px-6 sm:py-10">
157	        <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
158	          <CardHeader className="border-border/60 space-y-4 border-b pb-6 sm:pb-6">
159	            <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
160	              <div className="space-y-2">
161	                <Badge variant="secondary">Numbers4</Badge>
162	                <CardTitle className="font-heading text-xl sm:text-2xl">
163	                  当選番号一覧
164	                </CardTitle>
165	                <CardDescription className="text-pretty max-w-2xl text-sm leading-relaxed sm:text-base">
166	                  回号の新しい順に表示しています。狭い画面では表を横にスクロールできます。ページは
167	                  URL の{" "}
168	                  <code className="bg-muted rounded-md px-1.5 py-0.5 font-mono text-xs">
169	                    page
170	                  </code>{" "}
171	                  でも切り替わります。
172	                </CardDescription>
173	              </div>
