1	import { promises as fs } from "node:fs";
2	import path from "node:path";
3	import { cache } from "react";
4	
5	import { createClient } from "@/lib/supabase/server";
6	import type { Numbers4DrawRow } from "@/lib/numbers4";
7	
8	import {
9	  FALLBACK_BUDGET_6949,
10	  FALLBACK_ENSEMBLE_6949,
11	  FALLBACK_METHOD_ROWS,
12	  FALLBACK_TARGET_DRAW,
13	} from "./fallback-6949";
14	import { contributorsForEnsembleNumber } from "./ensemble-contributors";
15	import { normalizeNumbers4 } from "./prediction-hit-utils";
16	import { summarizeMethodPayload } from "./summarize-method";
17	import type {
18	  BudgetPlanPayload,
19	  EnsemblePayload,
20	  EnsemblePredictionRun,
21	  MethodPredictionRow,
22	  Numbers4DrawWinningModelHit,
23	  Numbers4PredictionBundle,
24	} from "./types";
25	
26	async function readJsonFile<T>(filePath: string): Promise<T | null> {
27	  try {
28	    const raw = await fs.readFile(filePath, "utf-8");
29	    return JSON.parse(raw) as T;
30	  } catch {
31	    return null;
32	  }
33	}
34	
35	async function maxDrawFromFilesystem(repoRoot: string): Promise<number | null> {
36	  const daily = path.join(repoRoot, "predictions", "daily");
37	  try {
38	    const names = await fs.readdir(daily);
39	    let max = -1;
40	    const re = /^numbers4_(\d+)\.json$/;
41	    for (const name of names) {
42	      const m = name.match(re);
43	      if (m) max = Math.max(max, parseInt(m[1], 10));
44	    }
45	    return max >= 0 ? max : null;
46	  } catch {
47	    return null;
48	  }
49	}
50	
51	async function maxDrawFromSupabase(): Promise<number | null> {
52	  try {
53	    const supabase = await createClient();
54	    const { data, error } = await supabase
55	      .from("numbers4_daily_prediction_documents")
56	      .select("target_draw_number")
57	      .eq("doc_kind", "ensemble")
58	      .order("target_draw_number", { ascending: false })
59	      .limit(1);
60	    if (error || !data?.length) return null;
61	    const n = data[0].target_draw_number;
62	    return typeof n === "number" && n > 0 ? n : null;
63	  } catch {
64	    return null;
65	  }
66	}
67	
68	/** DB・リポジトリのいずれかで最新とみなす対象回号 */
69	export async function resolveTargetDrawNumber(): Promise<number> {
70	  const repoRoot = path.join(process.cwd(), "..", "..");
71	  const [fromDb, fromFs] = await Promise.all([
72	    maxDrawFromSupabase(),
73	    maxDrawFromFilesystem(repoRoot),
74	  ]);
75	  const cands = [fromDb, fromFs].filter(
76	    (x): x is number => x != null && x > 0,
77	  );
78	  if (cands.length === 0) return FALLBACK_TARGET_DRAW;
79	  return Math.max(...cands);
80	}
81	
82	type DbDocRow = {
83	  doc_kind: string;
84	  method_slug: string | null;
85	  payload: unknown;
86	  relative_path: string | null;
87	};
88	
89	async function loadBundleFromDatabase(
90	  targetDrawNumber: number,
91	): Promise<
92	  Pick<
93	    Numbers4PredictionBundle,
94	    "ensemble" | "budgetPlan" | "methodRows"
95	  > | null
96	> {
97	  const supabase = await createClient();
98	  const { data: rows, error } = await supabase
99	    .from("numbers4_daily_prediction_documents")
100	    .select("doc_kind, method_slug, payload, relative_path")
101	    .eq("target_draw_number", targetDrawNumber);
102	
103	  if (error || !rows?.length) return null;
104	
105	  let ensemble: EnsemblePayload | null = null;
106	  let budgetPlan: BudgetPlanPayload | null = null;
107	  const methodRows: MethodPredictionRow[] = [];
108	
109	  for (const row of rows as DbDocRow[]) {
110	    if (row.doc_kind === "ensemble") {
111	      ensemble = row.payload as EnsemblePayload;
112	    } else if (row.doc_kind === "budget_plan") {
113	      budgetPlan = row.payload as BudgetPlanPayload;
114	    } else if (row.doc_kind === "method" && row.method_slug) {
115	      methodRows.push({
116	        slug: row.method_slug,
117	        relativePath: row.relative_path,
118	        ...summarizeMethodPayload(row.payload),
119	      });
120	    }
121	  }
122	
123	  methodRows.sort((a, b) => a.slug.localeCompare(b.slug));
124	  return { ensemble, budgetPlan, methodRows };
125	}
126	
127	async function scanMethodsForDraw(
128	  repoRoot: string,
129	  drawNumber: number,
130	): Promise<MethodPredictionRow[]> {
131	  const base = path.join(repoRoot, "predictions", "daily", "methods");
132	  const fname = `numbers4_${drawNumber}.json`;
133	  const rows: MethodPredictionRow[] = [];
134	  try {
135	    const entries = await fs.readdir(base, { withFileTypes: true });
136	    for (const ent of entries) {
137	      if (!ent.isDirectory()) continue;
138	      const fp = path.join(base, ent.name, fname);
139	      const payload = await readJsonFile<unknown>(fp);
140	      if (payload === null) continue;
141	      const rel = path.relative(repoRoot, fp).split(path.sep).join("/");
142	      rows.push({
143	        slug: ent.name,
144	        relativePath: rel,
145	        ...summarizeMethodPayload(payload),
146	      });
147	    }
148	  } catch {
149	    /* methods なし */
150	  }
151	  return rows.sort((a, b) => a.slug.localeCompare(b.slug));
152	}
153	
154	type DbMethodDocRow = {
155	  target_draw_number: number;
156	  method_slug: string | null;
157	  payload: unknown;
158	  relative_path: string | null;
159	};
160	
161	/**
162	 * 複数回分の method ドキュメントをまとめて取得（DB 一括 → 欠けはリポジトリ JSON で補完）。
163	 */
164	async function fetchMethodRowsGroupedByDraw(
165	  drawNumbers: number[],
166	): Promise<Map<number, MethodPredictionRow[]>> {
167	  const uniq = [...new Set(drawNumbers)].filter(
168	    (n) => Number.isFinite(n) && n > 0,
169	  ) as number[];
170	  const map = new Map<number, MethodPredictionRow[]>();
171	  for (const d of uniq) map.set(d, []);
172	
173	  if (uniq.length === 0) return map;
174	
175	  try {
176	    const supabase = await createClient();
177	    const { data, error } = await supabase
178	      .from("numbers4_daily_prediction_documents")
179	      .select("target_draw_number, method_slug, payload, relative_path")
180	      .eq("doc_kind", "method")
181	      .in("target_draw_number", uniq);
182	
183	    if (!error && data?.length) {
184	      for (const row of data as DbMethodDocRow[]) {
185	        const tn = row.target_draw_number;
186	        if (!row.method_slug || !Number.isFinite(tn)) continue;
187	        const cur = map.get(tn) ?? [];
188	        cur.push({
189	          slug: row.method_slug,
190	          relativePath: row.relative_path,
191	          ...summarizeMethodPayload(row.payload),
192	        });
193	        map.set(tn, cur);
194	      }
195	      for (const tn of uniq) {
196	        const cur = map.get(tn) ?? [];
197	        cur.sort((a, b) => a.slug.localeCompare(b.slug));
198	        map.set(tn, cur);
199	      }
200	    }
201	  } catch {
202	    /* FS で補完 */
203	  }
204	
205	  const repoRoot = path.join(process.cwd(), "..", "..");
206	  const missing = uniq.filter((d) => (map.get(d) ?? []).length === 0);
207	  const batchSize = 8;
208	  for (let i = 0; i < missing.length; i += batchSize) {
209	    const chunk = missing.slice(i, i + batchSize);
210	    const results = await Promise.all(
211	      chunk.map(async (d) => {
212	        const rows = await scanMethodsForDraw(repoRoot, d);
213	        return [d, rows] as const;
214	      }),
215	    );
216	    for (const [d, rows] of results) {
217	      map.set(d, rows);
218	    }
219	  }
220	
221	  return map;
222	}
223	
224	/**
225	 * 当選番号ごとに、各モデル候補（最大96件）へストレート／ボックスで入っていた slug を列挙する。
226	 */
227	export async function buildWinningModelHitsForDrawList(
