import { createServerClient } from "@supabase/ssr";
import { cookies } from "next/headers";

import { requirePublicSupabaseConfig } from "@/lib/env";

export async function createClient() {
  const cookieStore = await cookies();
  const { url, anonKey } = requirePublicSupabaseConfig();

  return createServerClient(url, anonKey, {
    cookies: {
      getAll() {
        return cookieStore.getAll();
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) =>
            cookieStore.set(name, value, options),
          );
        } catch {
          // Server Component からの呼び出しなど、set できない場合は無視
        }
      },
    },
  });
}

import type { Metadata } from "next";
import Link from "next/link";
import { ArrowLeftIcon, LineChartIcon } from "lucide-react";

import { buttonVariants } from "@/components/ui/button-variants";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { buildBreadcrumbJsonLd } from "@/lib/breadcrumb-jsonld";
import { computeBoxRankStats } from "@/lib/numbers4-predictions/box-rank-stats";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

export const metadata: Metadata = {
  title: "ボックス順位の統計 | ナンバーズ4",
  description:
    "直近の開催回について、アンサンブル・手法別のモデル候補リスト内で当選番号（ボックス一致）が何位以内に入ったかを集計します（将来の当せんを約束するものではありません）。 EN: Box-rank stats for recent Numbers4 draws (unofficial).",
  alternates: { canonical: "/numbers4/stats" },
  openGraph: {
    title: "ボックス順位の統計 | ナンバーズ4",
    description:
      "各モデルの候補リスト内での当選番号の順位を集計して比較できます。",
    url: "/numbers4/stats",
  },
};

type PageProps = {
  searchParams: Promise<{ last?: string; topK?: string }>;
};

function parsePositiveInt(v: string | undefined, fallback: number): number {
  if (v == null || v === "") return fallback;
  const n = parseInt(v, 10);
  return Number.isFinite(n) && n > 0 ? n : fallback;
}

export default async function Numbers4StatsPage({ searchParams }: PageProps) {
  const sp = await searchParams;
  const last = parsePositiveInt(sp.last, 20);
  const topK = parsePositiveInt(sp.topK, 100);

  const stats = await computeBoxRankStats({ lastN: last, topK });

  const lastOptions = [10, 20, 30, 50] as const;
  const topKOptions = [50, 100, 200] as const;

  const mkHref = (l: number, k: number) =>
    `/numbers4/stats?last=${l}&topK=${k}`;

  const breadcrumbJsonLd = buildBreadcrumbJsonLd([
    { name: "ナンバーズ4", path: "/numbers4" },
    { name: "ボックス順位の統計", path: "/numbers4/stats" },
  ]);

  return (
    <div className="flex flex-1 flex-col">
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
      />
      <div className="mx-auto w-full max-w-6xl flex-1 space-y-8 px-4 py-10 sm:px-6 sm:py-14">
        <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
          <div className="space-y-2">
            <Link
              href="/numbers4"
              className={cn(
                buttonVariants({ variant: "ghost", size: "sm" }),
                "text-muted-foreground -ml-2 w-fit gap-1",
              )}
            >
              <ArrowLeftIcon className="size-4" />
              ナンバーズ4 トップへ
            </Link>
            <div className="flex items-center gap-2">
              <LineChartIcon className="text-muted-foreground size-7" />
              <h1 className="text-foreground font-heading text-2xl font-semibold tracking-tight sm:text-3xl">
                ボックス順位の統計
              </h1>
            </div>
            <p className="text-muted-foreground max-w-2xl text-sm leading-relaxed">
              当サイトに取り込まれた当選番号がある直近{" "}
              <strong className="text-foreground">{stats.draws.length}</strong>{" "}
              回を対象に、各回のモデル試算バンドル（オンラインの最新を優先し、無ければサイト同梱の日次
              JSON）から<strong className="text-foreground">
                ボックス一致
              </strong>
              が<strong className="text-foreground">
                リスト先頭から何番目か
              </strong>
              を数え、しきい値ごとの割合を出しています。JSON
              に保存されている件数（例: アンサンブル上位
              20）より下は「圏外」になります。
            </p>
          </div>
        </div>

        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-lg">条件</CardTitle>
            <CardDescription>
              対象回数・評価するリスト長を切り替えます（いずれも URL
              クエリに反映）。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4 sm:flex-row sm:flex-wrap sm:items-center">
            <div className="space-y-1">
              <p className="text-muted-foreground text-xs font-medium">
                直近の開催回（当選データあり）
              </p>
              <div className="flex flex-wrap gap-2">
                {lastOptions.map((l) => (
                  <Link
                    key={l}
                    href={mkHref(l, topK)}
                    className={cn(
                      buttonVariants({
                        variant: l === last ? "default" : "outline",
                        size: "sm",
                      }),
                    )}
                  >
                    {l} 回
                  </Link>
                ))}
              </div>
            </div>
            <div className="space-y-1">
              <p className="text-muted-foreground text-xs font-medium">
                リスト先頭から探索する最大件数（top K）
              </p>
              <div className="flex flex-wrap gap-2">
                {topKOptions.map((k) => (
                  <Link
                    key={k}
                    href={mkHref(last, k)}
                    className={cn(
                      buttonVariants({
                        variant: k === topK ? "default" : "outline",
                        size: "sm",
                      }),
                    )}
                  >
                    {k} 件まで
                  </Link>
                ))}
              </div>
            </div>
          </CardContent>
        </Card>

        {!stats.hadSupabaseDraws ? (
          <Card className="border-destructive/40 bg-destructive/5">
            <CardHeader>
              <CardTitle className="text-base text-destructive">
                データを取得できませんでした
              </CardTitle>
              <CardDescription>
                当選番号付きの抽選結果を読み込めませんでした。データ未投入・公開サイト側の設定・接続状況を確認してください。
              </CardDescription>
            </CardHeader>
          </Card>
        ) : (
          <>
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-lg">集計サマリー</CardTitle>
                <CardDescription>
                  n = 対象回数。圏外 = その回の保存リスト内にボックス一致が無い（または当選不明）。
                  列「≤5」は 5 位以内にボックス一致があった回の割合。
                </CardDescription>
              </CardHeader>
              <CardContent className="px-0 sm:px-6">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="min-w-[200px]">ソース</TableHead>
                      <TableHead className="text-right">n</TableHead>
                      <TableHead className="text-right">圏外</TableHead>
                      {stats.thresholds.map((t) => (
                        <TableHead key={t} className="text-right">
                          ≤{t}
                        </TableHead>
                      ))}
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {stats.aggregates.map((row) => (
                      <TableRow key={row.key}>
                        <TableCell className="font-medium whitespace-normal">
                          {row.label}
                        </TableCell>
                        <TableCell className="text-right tabular-nums">
                          {row.n}
                        </TableCell>
                        <TableCell className="text-right tabular-nums">
                          {row.outOfRange}
                        </TableCell>
                        {stats.thresholds.map((t) => {
                          const cell = row.atOrBelow[t];
                          return (
                            <TableCell
                              key={t}
                              className="text-right tabular-nums text-xs sm:text-sm"
                            >
                              {cell
                                ? `${cell.count} (${cell.pct.toFixed(1)}%)`
                                : "—"}
                            </TableCell>
                          );
                        })}
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-lg">回別の順位（詳細）</CardTitle>
                <CardDescription>
                  数字はボックス一致の順位（1
                  始まり）。空欄は圏外。アンサンブル列は ensemble JSON
                  の最新スナップショットです。
                </CardDescription>
              </CardHeader>
              <CardContent className="px-0 sm:px-6">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="sticky left-0 z-10 bg-card min-w-[72px]">
                        回
                      </TableHead>
                      <TableHead className="min-w-[56px]">当選</TableHead>
                      <TableHead className="text-center min-w-[64px]">
                        Ens.
                      </TableHead>
                      {stats.aggregates
                        .filter((r) => r.key !== "ensemble")
                        .map((r) => (
                          <TableHead
                            key={r.key}
                            className="text-center min-w-[52px] max-w-[72px] truncate text-xs"
                            title={r.label}
                          >
                            {r.key}
                          </TableHead>
                        ))}
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {stats.perDraw.map((d) => (
                      <TableRow key={d.drawNumber}>
                        <TableCell className="bg-card sticky left-0 z-10 font-medium tabular-nums">
                          {d.drawNumber}
                        </TableCell>
                        <TableCell className="font-mono text-xs sm:text-sm">
                          {d.winning ?? "—"}
                        </TableCell>
                        <TableCell className="text-center tabular-nums text-xs sm:text-sm">
                          {d.ranks.ensemble ?? "—"}
                        </TableCell>
                        {stats.aggregates
                          .filter((x) => x.key !== "ensemble")
                          .map((x) => {
                            const slug = x.key;
                            const v = d.ranks[slug];
                            return (
                              <TableCell
                                key={slug}
                                className="text-center tabular-nums text-xs"
                              >
                                {v ?? "—"}
                              </TableCell>
                            );
                          })}
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </>
        )}
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import { ArrowLeftIcon, FlameIcon, WavesIcon, LightbulbIcon } from "lucide-react";
import Link from "next/link";

import { Badge } from "@/components/ui/badge";
import { buttonVariants } from "@/components/ui/button-variants";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { buildBreadcrumbJsonLd } from "@/lib/breadcrumb-jsonld";
import { loadNumbers4PredictionBundleForDraw, resolveTargetDrawNumber } from "@/lib/numbers4-predictions/load-6949";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

export const metadata: Metadata = {
  title: "Hot Model トレンド分析 | ナンバーズ4",
  description:
    "直近50回の成績から、いま一番「キテる」モデルを分析します（過去データの整理であり当せんを約束しません）。 EN: Hot model trend view for Numbers4 (unofficial).",
  alternates: { canonical: "/numbers4/trend" },
  openGraph: {
    title: "Hot Model トレンド分析 | ナンバーズ4",
    description:
      "直近のモデル試算の成績から注目モデルを可視化。当せんの保証はありません。",
    url: "/numbers4/trend",
  },
};

async function fetchTrendData(targetDraw: number) {
  try {
    const bundle = await loadNumbers4PredictionBundleForDraw(targetDraw);
    if (!bundle || !bundle.ensemble || !bundle.ensemble.predictions) {
      return { hotModels: [], recentFlow: [], nextPredictions: [] };
    }
    const preds = bundle.ensemble.predictions;
    const lastRun = preds[preds.length - 1];
    return {
      hotModels: lastRun.hot_models || [],
      recentFlow: [...(lastRun.recent_flow || [])].sort(
        (a, b) => (a.draw ?? 0) - (b.draw ?? 0),
      ),
      nextPredictions: lastRun.next_model_predictions || [],
    };
  } catch (error) {
    console.error("Failed to fetch trend data:", error);
    return { hotModels: [], recentFlow: [], nextPredictions: [] };
  }
}

export default async function HotModelTrendPage() {
  const latestDraw = await resolveTargetDrawNumber();
  const { hotModels, recentFlow, nextPredictions } = await fetchTrendData(latestDraw);

  const breadcrumbJsonLd = buildBreadcrumbJsonLd([
    { name: "ナンバーズ4", path: "/numbers4" },
    { name: "Hot Model トレンド分析", path: "/numbers4/trend" },
  ]);

  return (
    <div className="flex flex-1 flex-col">
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
      />
      <div className="mx-auto w-full max-w-3xl flex-1 space-y-8 px-4 py-10 sm:px-6 sm:py-14">
        <div className="flex items-start gap-4">
          <Link
            href="/numbers4"
            className={cn(
              buttonVariants({ variant: "ghost", size: "icon" }),
              "mt-1 shrink-0",
            )}
            aria-label="戻る"
          >
            <ArrowLeftIcon className="size-5" />
          </Link>
          <div>
            <Badge variant="secondary" className="mb-2">
              <FlameIcon data-icon="inline-start" className="size-3.5 text-orange-500" />
              Hot Model Trend
            </Badge>
            <h1 className="text-foreground font-heading text-2xl font-semibold tracking-tight sm:text-3xl">
              直近50回のトレンド分析
            </h1>
          </div>
        </div>

        <p className="text-muted-foreground text-sm leading-relaxed sm:text-base">
          第 {latestDraw - 50} 回 〜 第 {latestDraw - 1} 回の成績を集計し、
          いま一番「キテる」モデルをランキング形式で表示します。
          （※ このスコアは毎日のアンサンブル試算の重み付けに自動で反映されます）
        </p>

        {hotModels.length > 0 ? (
          <div className="space-y-6">
            <Card className="border-orange-500/20 bg-orange-500/5 shadow-sm">
              <CardHeader className="pb-3">
                <CardTitle className="flex items-center gap-2 text-lg text-orange-600 dark:text-orange-400">
                  <FlameIcon className="size-5" />
                  今一番キテるのは【{hotModels[0].model}】！
                </CardTitle>
                <CardDescription className="text-orange-700/80 dark:text-orange-300/80">
                  直近50回で最も高いスコア（{hotModels[0].score.toFixed(1)}）を獲得しています。
                  次回開催向けの試算では、このモデルの出力も比較材料のひとつです（当せんの保証ではありません）。
                </CardDescription>
              </CardHeader>
            </Card>

            <Card className="border-border/80 shadow-sm">
              <CardHeader>
                <CardTitle className="text-lg">🏆 Hot Model ランキング</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {hotModels.map((item, index) => {
                    const maxScore = hotModels[0].score || 1;
                    const percentage = Math.max(2, (item.score / maxScore) * 100);

                    let medal = "✨";
                    if (index === 0) medal = "🥇";
                    else if (index === 1) medal = "🥈";
                    else if (index === 2) medal = "🥉";

                    return (
                      <div key={item.model} className="space-y-1.5">
                        <div className="flex items-center justify-between text-sm">
                          <span className="font-medium flex items-center gap-2">
                            <span className="w-6 text-center">{medal}</span>
                            {item.model}
                          </span>
                          <span className="text-muted-foreground font-mono">
                            {item.score.toFixed(1)}
                          </span>
                        </div>
                        <div className="bg-muted h-2 w-full overflow-hidden rounded-full">
                          <div
                            className={cn(
                              "h-full rounded-full transition-all",
                              index === 0 ? "bg-orange-500" : 
                              index < 3 ? "bg-orange-400/70" : "bg-primary/40"
                            )}
                            style={{ width: `${percentage}%` }}
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </CardContent>
            </Card>

            {recentFlow.length > 0 && (
              <Card className="border-border/80 shadow-sm">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-lg">
                    <WavesIcon className="size-5 text-blue-500" />
                    直近の最強モデルのながれ
                  </CardTitle>
                  <CardDescription>
                    各回で最も成績が良かったモデルの履歴です（JSON では直近11回分を保存）。
                    モデルの「連チャン」や「遷移パターン」を読むヒントになります。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <ul className="space-y-2 font-mono text-sm">
                    {recentFlow.map((flow) => (
                      <li
                        key={flow.draw}
                        className="text-foreground flex flex-wrap items-baseline gap-x-2"
                      >
                        <span className="text-muted-foreground">• 第{flow.draw}回:</span>
                        <span>{flow.model}</span>
                        <span className="text-muted-foreground font-sans text-xs tabular-nums">
                          (スコア: {flow.score.toFixed(1)})
                        </span>
                      </li>
                    ))}
                  </ul>
                </CardContent>
              </Card>
            )}

            {nextPredictions.length > 0 && (
              <Card className="border-border/80 shadow-sm border-blue-500/20 bg-blue-500/5">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-lg text-blue-600 dark:text-blue-400">
                    <LightbulbIcon className="size-5" />
                    次回（第 {latestDraw} 回）向けの参考モデル順（過去遷移ベース）
                  </CardTitle>
                  <CardDescription className="text-blue-700/80 dark:text-blue-300/80">
                    過去50回の遷移に基づく参考ランキングです。前回（第 {latestDraw - 1}{" "}
                    回）でスコアが高かった「{recentFlow[recentFlow.length - 1]?.model}
                    」のあとに同じ傾向が続くとは限りません。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    {nextPredictions.map((pred, i) => (
                      <div key={pred.model} className="space-y-1.5">
                        <div className="flex items-center justify-between text-sm">
                          <span className="font-medium flex items-center gap-2">
                            <span className="w-6 text-center">{i === 0 ? "🎯" : "✨"}</span>
                            {pred.model}
                          </span>
                          <span className="text-muted-foreground text-xs">
                            確率: {(pred.probability * 100).toFixed(1)}% ({pred.count}/{pred.total}回)
                          </span>
                        </div>
                        <div className="bg-muted h-2 w-full overflow-hidden rounded-full">
                          <div
                            className={cn(
                              "h-full rounded-full transition-all",
                              i === 0 ? "bg-blue-500" : "bg-blue-400/50"
                            )}
                            style={{ width: `${Math.max(2, pred.probability * 100)}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>
        ) : (
          <Card className="border-border/80 shadow-sm">
            <CardContent className="py-10 text-center">
              <p className="text-muted-foreground">
                トレンドデータを取得できませんでした。
                Pythonスクリプトの実行環境を確認してください。
              </p>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import Link from "next/link";
import {
  ArrowRightIcon,
  DatabaseIcon,
  ListIcon,
  SparklesIcon,
} from "lucide-react";

import { Badge } from "@/components/ui/badge";
import { AnalysisTransparencyCallout } from "@/components/analysis-transparency-callout";
import { TodayReferencePanel } from "@/components/today-reference-panel";
import { buttonVariants } from "@/components/ui/button-variants";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Loto6PredictionsPanel } from "@/components/loto6-predictions-panel";
import { buildBreadcrumbJsonLd } from "@/lib/breadcrumb-jsonld";
import {
  loadLoto6PredictionBundle,
  resolveNextLoto6TargetDrawNumber,
} from "@/lib/loto6-predictions/load-bundles";
import { createClient } from "@/lib/supabase/server";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

export const metadata: Metadata = {
  title: "ロト6",
  description:
    "ロト6の当選番号一覧への入口です。本数字・ボーナス・等級別払戻を Supabase 上のデータから表示します。",
  alternates: { canonical: "/loto6" },
  openGraph: {
    title: "ロト6 | 宝くじAI",
    description:
      "ロト6の抽選結果一覧・詳細、MVPモデル試算、出現回数統計へのハブ。当せんの保証はありません。",
    url: "/loto6",
  },
};

export default async function Loto6Page() {
  const supabase = await createClient();
  const { data } = await supabase
    .from("loto6_draws")
    .select("draw_number")
    .order("draw_number", { ascending: false })
    .limit(1)
    .maybeSingle();

  const latestDraw = data?.draw_number ?? null;
  const latestHref = latestDraw ? `/loto6/result/${latestDraw}` : "/loto6/result";

  const nextTarget = await resolveNextLoto6TargetDrawNumber();
  const predictionBundle =
    nextTarget != null ? await loadLoto6PredictionBundle(nextTarget) : null;

  const breadcrumbJsonLd = buildBreadcrumbJsonLd([
    { name: "ロト6", path: "/loto6" },
  ]);

  return (
    <div className="flex flex-1 flex-col">
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
      />
      <div className="mx-auto w-full max-w-4xl flex-1 space-y-10 px-4 py-10 sm:space-y-12 sm:px-6 sm:py-14">
        <header className="space-y-4 text-center sm:text-left">
          <Badge
            variant="secondary"
            className="mb-1 border-amber-500/30 bg-amber-500/10 text-amber-900 dark:border-amber-400/30 dark:bg-amber-400/10 dark:text-amber-100"
          >
            <SparklesIcon data-icon="inline-start" className="size-3.5" />
            Loto6
          </Badge>
          <h1 className="text-foreground font-heading text-3xl font-semibold tracking-tight sm:text-4xl">
            ロト6
          </h1>
          <p className="text-muted-foreground mx-auto max-w-xl text-sm leading-relaxed sm:mx-0 sm:text-base">
            本サイトのロト6ゾーンです。最新取り込み回は{" "}
            <strong className="text-foreground">
              {latestDraw ? `第 ${latestDraw} 回` : "未取得"}
            </strong>
            です。当選番号・ボーナス・等級別口数・払戻金・キャリーオーバーを一覧・詳細で確認できます。
            {nextTarget != null ? (
              <>
                {" "}
                次回予定の{" "}
                <strong className="text-foreground">第 {nextTarget} 回</strong>
                向けの MVP モデル試算は、下のパネルで確認できます（データがある場合。当せんの保証ではありません）。
              </>
            ) : null}
          </p>
        </header>

        {predictionBundle &&
        (predictionBundle.ensemble != null ||
          predictionBundle.methodRows.length > 0) ? (
          <section className="border-border/60 rounded-2xl border bg-card/40 p-5 shadow-sm ring-1 ring-black/5 sm:p-6 dark:ring-white/10">
            <Loto6PredictionsPanel bundle={predictionBundle} />
          </section>
        ) : nextTarget != null ? (
          <Card className="border-dashed border-amber-500/30 bg-muted/20 shadow-none">
            <CardHeader className="pb-2">
              <CardTitle className="text-base">モデル試算（MVP）</CardTitle>
              <CardDescription>
                第 {nextTarget} 回向けの試算 JSON がまだ Supabase に入っていません。リポジトリで{" "}
                <code className="font-mono text-xs">
                  python tools/generate_loto6_predictions_mvp.py
                </code>{" "}
                →{" "}
                <code className="font-mono text-xs">
                  python tools/load_loto6_daily_json_to_postgres.py
                </code>{" "}
                を実行すると表示されます（8 手法 + アンサンブル JSON）。
              </CardDescription>
            </CardHeader>
          </Card>
        ) : null}

        <TodayReferencePanel
          title="Today view"
          latestLabel="最新取り込み / 次回参考対象"
          latestValue={`${latestDraw ? `取り込み: 第 ${latestDraw} 回` : "取り込み: 未取得"}${nextTarget != null ? ` / 次回: 第 ${nextTarget} 回` : ""}`}
          primaryHref={latestHref}
          primaryLabel={latestDraw ? `第 ${latestDraw} 回を見る` : "一覧を見る"}
          secondaryHref="/loto6/result"
          secondaryLabel="当選番号一覧"
          statsHref="/loto6/stats"
          statsLabel="出現回数の統計"
          apiHref="/api/loto6/latest"
          apiLabel="GET /api/loto6/latest"
          accentClassName="border-amber-500/20 bg-amber-500/5"
        />

        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
            <CardHeader className="pb-3">
              <CardTitle className="text-lg">最新回を見る</CardTitle>
              <CardDescription>
                最新回の当選結果ページに移動します。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Link
                href={latestHref}
                className={cn(
                  buttonVariants({ size: "lg" }),
                  "w-full justify-center gap-2 bg-gradient-to-r from-amber-600 to-orange-600 text-white shadow-sm hover:from-amber-500 hover:to-orange-500 sm:w-auto",
                )}
              >
                {latestDraw ? `第 ${latestDraw} 回へ` : "一覧へ"}
                <ArrowRightIcon className="size-4" />
              </Link>
            </CardContent>
          </Card>

          <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
            <CardHeader className="pb-3">
              <CardTitle className="text-lg">出現回数の統計</CardTitle>
              <CardDescription>
                本数字・ボーナスの出現頻度を球ごとにチェック。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Link
                href="/loto6/stats"
                className={cn(
                  buttonVariants({ variant: "outline", size: "lg" }),
                  "w-full justify-center gap-2 border-amber-500/30 sm:w-auto",
                )}
              >
                統計ページへ
                <ArrowRightIcon className="size-4" />
              </Link>
            </CardContent>
          </Card>

          <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
            <CardHeader className="pb-3">
              <div className="flex items-center gap-2">
                <ListIcon className="text-muted-foreground size-5" />
                <CardTitle className="text-lg">当選番号一覧</CardTitle>
              </div>
              <CardDescription>回号ごとの結果を一覧表示します。</CardDescription>
            </CardHeader>
            <CardContent>
              <Link
                href="/loto6/result"
                className={cn(
                  buttonVariants({ variant: "outline", size: "lg" }),
                  "w-full justify-center gap-2 border-amber-500/30 sm:w-auto",
                )}
              >
                一覧を開く
                <ArrowRightIcon className="size-4" />
              </Link>
            </CardContent>
          </Card>
        </div>

        <Card className="border-border/60 bg-muted/30 shadow-none">
          <CardHeader className="pb-2">
            <div className="flex items-center gap-2">
              <DatabaseIcon className="text-muted-foreground size-4" />
              <CardTitle className="text-base">データについて</CardTitle>
            </div>
            <CardDescription className="text-xs sm:text-sm">
              表示は Supabase の <code className="font-mono">loto6_draws</code>{" "}
              を参照します。非公式の二次情報です。購入判断は必ず公式発表で確認してください。
            </CardDescription>
          </CardHeader>
          <CardContent className="pt-0">
            <Link
              href="/data-sources"
              className={cn(
                buttonVariants({ variant: "link", size: "sm" }),
                "h-auto px-0 text-amber-700 dark:text-amber-400",
              )}
            >
              データの出所・API 一覧へ
            </Link>
          </CardContent>
        </Card>

        <AnalysisTransparencyCallout
          basis={[
            "公開された当選結果と、ある場合は日次の MVP モデル JSON を参照しています。",
            "一覧・統計・最新回ページをつないでいます。",
          ]}
          limitations={[
            "モデル表示は参考用で、当せん確率を保証しません。",
            "払戻やルールの最終確認は必ず公式情報で行ってください。",
          ]}
        />
      </div>
    </div>
  );
}

