                (item) => (
                  <div
                    key={item}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      padding: "10px 16px",
                      borderRadius: 999,
                      border: "1px solid rgba(33,25,15,0.08)",
                      background: "rgba(255,255,255,0.45)",
                      color: "#4d3d27",
                      fontSize: 20,
                    }}
                  >
                    {item}
                  </div>
                ),
              )}
            </div>
            <span
              style={{
                fontSize: 20,
                color: "rgba(75,61,39,0.54)",
                letterSpacing: "0.08em",
              }}
            >
              takarakuji-ai.space/en/blog/{slug}
            </span>
          </div>
        </div>
      </div>
    ),
    { ...size },
  );
}

