          lastModified: l6Iso ? new Date(`${l6Iso}T12:00:00.000Z`) : lastModified,
          changeFrequency: "weekly",
          priority: 0.52,
        });
      }
    }
  } catch {
    // ビルド時に Supabase 未接続などの場合は静的URLのみ
  }

